SELECT * FROM ( SELECT inner_q.*, ROWNUM rn FROM ( SELECT c.center_id AS centerId, c.center_name AS centerName, c.center_region AS centerRegion FROM centers c
AND c.center_name LIKE '%' || #{centerName} || '%'
AND c.center_region = #{region}
ORDER BY c.center_id DESC ) inner_q WHERE ROWNUM <= #{offset} + #{size} ) WHERE rn > #{offset}

SELECT COUNT(*) FROM centers c
AND c.center_name LIKE '%' || #{centerName} || '%'
AND c.center_region = #{region}
